// sparklinePoints generates SVG polyline points from data.
func sparklinePoints(data []int) string {
	if len(data) == 0 {
		return ""
	}
	min, max := data[0], data[0]
	for _, v := range data {
		if v < min {
			min = v
		}
		if v > max {
			max = v
		}
	}
	rangeVal := max - min
	if rangeVal == 0 {
		rangeVal = 1
	}
	var pts []string
	for i, v := range data {
		x := float64(i)
		y := 100.0 - (float64(v-min)/float64(rangeVal))*90.0 - 5.0
		pts = append(pts, formatPoint(x, y))
	}
	return strings.Join(pts, " ")
}

// sparklineFillArea generates polygon points for the filled area under the sparkline.
func sparklineFillArea(data []int) string {
	if len(data) == 0 {
		return ""
	}
	pts := "0 100 " + sparklinePoints(data) + " " + strconv.Itoa(len(data)-1) + " 100"
	return pts
}

// formatPoint formats a single SVG point coordinate.
func formatPoint(x, y float64) string {
	xi := int(x)
	yi := int(y)
	return strconv.Itoa(xi) + "," + strconv.Itoa(yi)
}

